import numpy as np
import matplotlib.pyplot as plt
from   matplotlib.backends.backend_pdf import PdfPages

def project(theta, phi):
    x = theta
    y = np.sin(theta) * (phi - np.pi) / np.pi
    return x, y


# def plot_event(particles, labels, title="Event display", pdf="event.pdf"):
    
# ------------------ conversion ------------------

def convert(data):
    particles = []
    labels = []
    for E, theta, phi, lab in data:
        particles.append({"E":E, "theta":theta, "phi":phi})
        labels.append(lab)
    return particles, labels

# plot
def plot_event(inputs, pdfname="event.pdf"):
    names = ["kt","ca","cen"]
    tits  = [r"$k_t$", "C/A", "Centauro"]
    with PdfPages(pdfname) as pdf: 
      for set in inputs.keys():
        print(set)
        input = inputs[set]
        xdis = input["x"]
        Q    = input["Q"]
        ydis = input["y"]
        data  = [input[name]["data"]  for name in names]
        macro = [input[name]["mlabel"] for name in names]
        # create the figure 
        fig, axs = plt.subplots(1, 3, figsize=(12,4))
        njets = 0
        for i, name in enumerate(names):
          particles, labels = convert(data[i])
          theta = np.array([p["theta"] for p in particles])
          phi   = np.array([p["phi"]   for p in particles])
          mom   = np.array([p["E"]     for p in particles])
          labels = np.array(labels)
          njets = np.max(labels)+1
          x, y = project(theta, phi)

          sizes = 10+10000 * (mom - mom.min()) / (mom.max() - mom.min() + 1e-9)
          cmap = plt.get_cmap("terrain")  # use terrain colormap for jet colours
          # cmap = plt.get_cmap("gist_rainbow")

          ax = axs[i]
          # θ grid — vertical straight lines
          for t in np.linspace(0, np.pi, 7):
              ph = np.linspace(0, 2*np.pi, 300)
              Xg, Yg = project(np.full_like(ph, t), ph)
              ax.plot(Xg, Yg, color='0.85', lw=1)

          # φ grid — curved horizontal lines
          for ph0 in [0, np.pi/2, np.pi, 3*np.pi/2, 2*np.pi]:
              th = np.linspace(0, np.pi, 300)
              Xg, Yg = project(th, np.full_like(th, ph0))
              ax.plot(Xg, Yg, color='0.85', lw=1)

          # φ labels at θ=π/2
          phi_labels = [(0, r'$\phi=-\pi$'),
                        (np.pi/2, r'$\phi=-\pi/2$'),
                        (np.pi, r'$\phi=0$'),
                        (3*np.pi/2, r'$\phi=\pi/2$'),
                        (2*np.pi, r'$\phi=\pi$')]
          for ph0, label in phi_labels:
              xpos, ypos = project(np.pi/2, ph0)
              ax.text(xpos, ypos, label, ha='center', va='center', fontsize=9, color='gray')

          # Particles
          for lab in np.unique(labels):
              m = labels == lab
              if lab == macro[i]:
                  # macrojet: red fill and border
                  c = 'red'
                  ec = 'black'
                  lw=0.6
                  alpha=0.85
              else:
                  # use terrain colormap normalized by number of jets
                  norm = lab / max(1, njets-1)
                  c = cmap(norm)
                  ec = 'gray'
                  lw = 0.4
                  alpha=0.6
              ax.scatter(x[m], y[m],
                        s=sizes[m],
                        color=c,
                        edgecolors=ec,
                        linewidth=lw,
                        alpha=alpha,
                        label=f"Cluster {lab}")

          ax.set_xlim(-0.2, np.pi+0.2)
          ax.set_ylim(-1.1, 1.1)
          # Add theta labels
          ax.text(0-0.25, 0.06, r'$\theta=0$', ha='center', va='top', fontsize=10)
          #ax.text(np.pi/2-0.05, 0.06, r'$\theta=\pi/2$', ha='center', va='top', fontsize=10)
          ax.text(np.pi+0.15, 0.06, r'$\theta=\pi$', ha='center', va='top', fontsize=10)
          # Remove axes and frame
          ax.set_axis_off()
          # hemisphere labels
          ax.text(0.01, 0.995, 'Remnant', transform=ax.transAxes, ha='left', va='top', fontsize=8)
          ax.text(0.99, 0.985, 'Current', transform=ax.transAxes, ha='right', va='top', fontsize=8)
          # ax.legend(ncol=2, fontsize=8, loc="upper left")
          ax.text(-.10, 0.05, f"{tits[i]}, $n_{{\\rm jets}}$ ={njets} " , horizontalalignment='left', verticalalignment='top', transform=ax.transAxes, color="black") #'#616161')
          ax.set_aspect("auto")
          ax.grid(False)
        axs[1].set_title(f"$x_{{\\rm B}}$={round(xdis,3)}, $Q$={round(Q,1)}GeV")  
        # plt.show()
        pdf.savefig(fig, bbox_inches='tight')
        # close the figure
        plt.close(fig)

